MERGE INTO TB_HQ_PRODUCT_INFO
USING DUAL
ON (
    HQ_OFFICE_CD = #{hqOfficeCd}
AND PROD_CD      = #{prodCd}
)
WHEN MATCHED THEN
UPDATE
SET
    PROD_KO_NM_DISP = 
,   PROD_KO_NM_DISP_KIOSK = 
,   MOD_DT       = #{modDt}
,   MOD_ID       = #{modId}
WHEN NOT MATCHED THEN
INSERT
(
    HQ_OFFICE_CD
,   PROD_CD
,   PROD_KO_NM_DISP
,   PROD_KO_NM_DISP_KIOSK
,   REG_DT
,   REG_ID
,   MOD_DT
,   MOD_ID
)
VALUES
(
    #{hqOfficeCd}
,   #{prodCd}
,   
,   
,   #{regDt}
,   #{regId}
,   #{modDt}
,   #{modId}
)
